1	/**
2	 * GraphQL Client for Nexus CLI
3	 *
4	 * Connects to Local's GraphQL server and executes queries/mutations.
5	 */
6	
7	import { readConnectionInfo } from '../bootstrap/graphql';
8	import type { ConnectionInfo } from '../bootstrap/graphql';
9	
10	export { ConnectionInfo } from '../bootstrap/graphql';
11	
12	export class GraphQLClientError extends Error {
13	  constructor(
14	    message: string,
15	    public errors?: Array<{ message: string; path?: string[] }>
16	  ) {
17	    super(message);
18	    this.name = 'GraphQLClientError';
19	  }
20	}
21	
22	export class GraphQLClient {
23	  private connectionInfo: ConnectionInfo;
24	  private timeout: number;
25	
26	  constructor(connectionInfo?: ConnectionInfo, options?: { timeout?: number }) {
27	    this.connectionInfo = connectionInfo || this.loadConnectionInfo();
28	    this.timeout = options?.timeout || 30000;
29	  }
30	
31	  /**
32	   * Load connection info from Local's userData
33	   */
34	  private loadConnectionInfo(): ConnectionInfo {
35	    const info = readConnectionInfo();
36	    if (!info) {
37	      throw new Error(
38	        'Local is not running or GraphQL server is not ready.\n\n' +
39	          'Please start Local first, or run with DEBUG=true for more info.'
40	      );
41	    }
42	    return info;
43	  }
44	
45	  /**
46	   * Execute a GraphQL query or mutation
47	   */
48	  async query<T = any>(query: string, variables?: Record<string, any>): Promise<T> {
49	    // Try the URL from connection file first, then fallback to port 4000
50	    // (Local's connection file sometimes has stale ports)
51	    const urlsToTry = [
52	      this.connectionInfo.url,
53	      'http://127.0.0.1:4000/graphql',
54	    ];
55	
56	    let lastError: any;
57	
58	    for (const url of urlsToTry) {
59	      const controller = new AbortController();
60	      const timeoutId = setTimeout(() => controller.abort(), this.timeout);
61	
62	      try {
63	        const response = await fetch(url, {
64	          method: 'POST',
65	          headers: {
66	            'Content-Type': 'application/json',
67	            Authorization: `Bearer ${this.connectionInfo.authToken}`,
68	          },
69	          body: JSON.stringify({
70	            query,
71	            variables: variables || {},
72	          }),
73	          signal: controller.signal,
74	        });
75	
76	        clearTimeout(timeoutId);
77	
78	        if (!response.ok) {
79	          throw new GraphQLClientError(
80	            `HTTP ${response.status}: ${response.statusText}`
81	          );
82	        }
83	
84	        const result = await response.json();
85	
86	        // Check for GraphQL errors
87	        if (result.errors && result.errors.length > 0) {
88	          const error = result.errors[0];
89	          throw new GraphQLClientError(error.message, result.errors);
90	        }
91	
92	        // Check for missing data
93	        if (result.data === null || result.data === undefined) {
94	          throw new GraphQLClientError('No data in response');
95	        }
96	
97	        // Success - update connection info to use working URL
98	        if (url !== this.connectionInfo.url) {
99	          this.connectionInfo.url = url;
100	        }
101	
102	        return result.data as T;
103	      } catch (error: any) {
104	        lastError = error;
105	        clearTimeout(timeoutId);
106	
107	        // If this was an abort (timeout), don't try other URLs
108	        if (error.name === 'AbortError') {
109	          throw new GraphQLClientError(
110	            `Request timed out after ${this.timeout / 1000}s`
111	          );
112	        }
113	
114	        // If GraphQL error (server responded but query failed), don't try other URLs
115	        if (error instanceof GraphQLClientError && !error.message.includes('Network')) {
116	          throw error;
117	        }
118	
119	        // Network error - try next URL
120	      }
121	    }
122	
123	    // All URLs failed - throw last error
124	
125	    if (lastError instanceof GraphQLClientError) {
126	      throw lastError;
127	    }
128	    throw new GraphQLClientError(`Network error: ${lastError?.message || 'Unknown error'}`);
129	  }
130	
131	  /**
132	   * Execute a GraphQL mutation (alias for query)
133	   */
134	  async mutate<T = any>(mutation: string, variables?: Record<string, any>): Promise<T> {
135	    return this.query<T>(mutation, variables);
136	  }
137	}
138	
139	/**
